/**
 * Emits an index.ts barrel file that re-exports all generated modules.
 */

import { toGrammarTypeName } from '../naming.ts';

export interface EmitIndexConfig {
  grammar: string;
  nodeKinds: string[];
}

export function emitIndex(config: EmitIndexConfig): string {
  const { grammar } = config;
  const grammarTypeName = toGrammarTypeName(grammar);
  const grammarPrefix = grammarTypeName.slice(0, -5);

  const lines: string[] = [
    '// Auto-generated by ir-codegen — do not edit',
    '',
    '// Types (grammar + projected IR nodes)',
    `export * from './types.js';`,
    '',
    '// Builders (ir namespace with branch + leaf builders)',
    `export { ir } from './builder.js';`,
    '',
    '// Constants (node kinds, keywords, operators, field maps)',
    `export * from './consts.js';`,
    '',
    '// Base builder + leaf builder (re-export from @sittir/types)',
    `export { BaseBuilder, LeafBuilder } from '@sittir/types';`,
    `export type { RenderContext } from '@sittir/types';`,
    '',
  ];

  return lines.join('\n');
}
